using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));
    dist[0][0][1] = (0 + 1) * (0 + 1);
    priority_queue<tuple<long long, long long, long long, long long>, vector<tuple<long long, long long, long long, long long>>, greater<>> pq;
    pq.push({dist[0][0][1], 0, 0, 1});

    while (!pq.empty()) {
        auto [current_cost, i, j, parity] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (current_cost > dist[i][j][parity]) {
            continue;
        }

        if (parity == 0) {
            long long new_cost = current_cost + waitCost[i][j];
            if (new_cost < dist[i][j][1]) {
                dist[i][j][1] = new_cost;
                pq.push({new_cost, i, j, 1});
            }
        } else {
            if (j + 1 < n) {
                long long new_i = i, new_j = j + 1;
                long long new_cost = current_cost + (new_i + 1) * (new_j + 1);
                if (new_cost < dist[new_i][new_j][0]) {
                    dist[new_i][new_j][0] = new_cost;
                    pq.push({new_cost, new_i, new_j, 0});
                }
            }
            if (i + 1 < m) {
                long long new_i = i + 1, new_j = j;
                long long new_cost = current_cost + (new_i + 1) * (new_j + 1);
                if (new_cost < dist[new_i][new_j][0]) {
                    dist[new_i][new_j][0] = new_cost;
                    pq.push({new_cost, new_i, new_j, 0});
                }
            }
        }
    }
    return -1;
}
